settings.custom_liquid:
{% if collection.handle == 'the-armory' %}
<div class="system-spec-banner">
  <div class="spec-border">
    <div class="spec-content">
      <div class="spec-header">
        <span class="blink-dot"></span> SYSTEM SPEC: THE LIVING DOCUMENT
      </div>
      <p class="spec-body">
        Every garment in the Armory features a high-density QR code on the left sleeve. 
        <strong>Scan to access the full source code of the U.S. Constitution instantly.</strong> 
        Troubleshoot the system. Carry the document.
      </p>
    </div>
  </div>
</div>

<style>
.system-spec-banner {
  background-color: #0A0A08; /* Using the black from your design system */
  padding: 20px;
  margin-bottom: 30px;
  font-family: 'Barlow Condensed', sans-serif; /* Using your tactical font */
}
.spec-border {
  border: 1px solid #A82020; /* Stamped Red */
  padding: 15px;
  position: relative;
}
.spec-header {
  color: #A82020;
  font-weight: 700;
  letter-spacing: 2px;
  font-size: 1.2rem;
  margin-bottom: 10px;
  display: flex;
  align-items: center;
}
.spec-body {
  color: #F0EBE0; /* Parchment White */
  margin: 0;
  font-size: 1rem;
  line-height: 1.4;
  text-transform: uppercase;
}
.blink-dot {
  height: 8px;
  width: 8px;
  background-color: #A82020;
  border-radius: 50%;
  display: inline-block;
  margin-right: 10px;
  animation: blink 1.5s infinite;
}
@keyframes blink {
  0% { opacity: 1; }
  50% { opacity: 0.3; }
  100% { opacity: 1; }
}
</style>
{% endif %}
